_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 uv6 = vUv;
vUv = vUv + vec2 (q6,q7);
vec2 uv1 = (vUv-.5 )*uAspect.xy;

//Kugel1
rsk = (uv1 + vec2 (q11,q12)) ;
dz1 = normalize(rsk);
rad1 = 8*(q13)*length(rsk) ;
uv4 =  tan(rad1)*dz1;
mask1 = clamp01(10-7*rad1);
Kugel1 = uv4*mask1/(1+q13);

//Kugel2
rsk = (uv1 + vec2 (q14,q15)) ;
dz1 = normalize(rsk);
rad2 = 2*(1+q16)*length(rsk+.1) ;
uv4 =  tan(rad2)*dz1;
mask2 = clamp01(10-7*rad2);
Kugel2 = uv4*mask2/(1+q16);

//Kugel3
rsk = (uv1 + vec2 (q17,q18)) ;
dz1 = normalize(rsk);
rad3 = 4*(1+q19)*length(rsk) ;
uv4 =  tan(rad3)*dz1;
mask3 = clamp01(10-7*rad3);
Kugel3 = uv4*mask3/(1+q19);

uv1 += (Kugel1 + Kugel2 + Kugel3)*.5;
float z = 1/(uv1.y+uv1.x*q5);
rs0.x = (uv1.x)*z;
rs0.y = z/4;
rs.x = rs0.x ;
rs.y = rs0.y + uTime*2;

//uv1 = multiply(uv1,mat2(_qa));
noise = lum(texture(sampler_noise_lq,rs/16));

float mask = clamp01(4/z);
uv2 = .4*uv1 * (length(uv1)+1);
uv2 *= uAspect.yx;
uv3 =fract(uv2+.5-(noise-.5)*mask*.2);

float xx = uv6.x*2562;
float yy = uv6.y*2562;
float ran = (xx*yy)% 13333 ;
vec3 stars = clamp01(1/ran) * (1-4*mask);


ret1 =  texture(sampler_main, uv3)*0.8;
ret1 += .2*q22*(q27%3)/rad1+
        .2*q22*((q27+1)%3)/rad2+
        .2*q22*((q27+2)%3)/rad3;
ret1 += .4*mask1*GetBlur1(0) + .4*mask2*GetBlur1(0.1) + .4*mask3*GetBlur1(0.2);
ret = max(ret1,stars);

  fragColor = ret;
}
